sys_script.script:
(function executeRule(current, previous) {

    var reqSysId = current.request.toString();
    if (!reqSysId) return;

    // 1. Check if all RITMs under this REQ have been decided (not 'requested')
    var allRITMs = new GlideRecord('sc_req_item');
    allRITMs.addQuery('request', reqSysId);
    allRITMs.query();
    var allDecided = true;
    while (allRITMs.next()) {
        if (allRITMs.approval_state == 'requested') {
            allDecided = false;
            break;
        }
    }
    if (!allDecided) return;

    // 2. Prevent duplicate events (using custom field on REQ)
    var req = new GlideRecord('sc_request');
    if (!req.get(reqSysId)) return;
    if (req.u_approval_emails_sent == true) return;

    // 3. Build the medicine list (to be passed as parameter, or we can build it inside notification)
    //    Instead of building the list here, we can pass reqSysId and let the notification query the data.
    //    But for simplicity, we can build the list and pass as parm2 (limited length).
    //    Alternatively, we can build it in a Script Include and call it from the notification.
    //    I'll pass reqSysId and let the notification's mail script fetch the list.

    // 4. Fire event with reqSys_id as parm1 and req number as parm2 (optional)
    gs.eventQueue('x_1971078_smart_0.pulse.all.approvals.co', current, reqSysId, req.number);

    // 5. Mark that event has been fired (to prevent duplicates)
    req.u_approval_emails_sent = true;
    req.update();

    gs.info('Event pulse.all.approvals.completed fired for REQ ' + req.number);

})(current, previous);
